document.addEventListener('DOMContentLoaded',()=>{const searchInput=document.getElementById('search-input');const searchResults=document.getElementById('search-results');if(!searchInput)return;const pages=[{t: "Bouddhisme",u: "/bouddhisme",d: "Histoire,écoles,maîtres"},{t: "Méditation",u: "/meditation",d: "Débuter,techniques,pleine conscience"},{t: "Philosophie",u: "/philosophie",d: "Karma,compassion,éveil"},{t: "Culture",u: "/culture",d: "Symboles,temples,pays"},{t: "Guides",u: "/guides",d: "Espace,quotidien,bien-être"},{t: "Glossaire",u: "/glossaire",d: "50 termes bouddhistes"},{t: "FAQ",u: "/faq",d: "30 questions fréquentes"},{t: "À propos",u: "/a-propos",d: "Ligne éditoriale"},{t: "Karma",u: "/philosophie/karma",d: "La loi de cause à effet"},{t: "Theravāda",u: "/bouddhisme/theravada",d: "Voie des Anciens"},{t: "Mahāyāna",u: "/bouddhisme/mahayana",d: "Grand Véhicule"},{t: "Vajrayāna",u: "/bouddhisme/vajrayana",d: "Véhicule de diamant"},{t: "Pleine conscience",u: "/meditation/pleine-conscience",d: "Mindfulness"},{t: "Zen",u: "/meditation/zen",d: "Méditation assise"},{t: "Symboles du bouddha",u: "/culture/symboles-bouddha",d: "Mudra,lotus"}];let timeout=null;searchInput.addEventListener('input',()=>{clearTimeout(timeout);const q=searchInput.value.trim().toLowerCase();if(q.length<2){searchResults.style.display='none';searchResults.innerHTML='';return;}timeout=setTimeout(()=>{const matches=pages.filter(p=>p.t.toLowerCase().includes(q)|| p.d.toLowerCase().includes(q)).slice(0,8);if(matches.length===0){searchResults.innerHTML='<div style="padding:1rem;color:var(--text-light);text-align:center;">Aucun résultat</div>';}else{searchResults.innerHTML=matches.map(p=>`<a href="${p.u}" class="search-item" style="display:flex;align-items:center;gap:1rem;padding:0.8rem;text-decoration:none;color:inherit;border-bottom:1px solid var(--beige);transition:background 0.2s;"><div><div style="font-weight:600;font-size:0.95rem;">${p.t}</div><div style="color:var(--gold-dark);font-size:0.85rem;">${p.d}</div></div></a>`).join('');}searchResults.style.display='block';},200);});document.addEventListener('click',(e)=>{if(!e.target.closest('.search-box')){searchResults.style.display='none';}});});